  1→#include "LFP2D/WorldMap/LFPWorldMapPlayerController.h"
  2→#include "LFP2D/WorldMap/LFPWorldMapManager.h"
  3→#include "LFP2D/WorldMap/LFPWorldMapNode.h"
  4→#include "LFP2D/WorldMap/LFPWorldMapPawn.h"
  5→#include "LFP2D/WorldMap/LFPWorldMapPlayerState.h"
  6→#include "LFP2D/WorldMap/LFPWorldMapEditorComponent.h"
  7→#include "LFP2D/UI/WorldMapEditor/LFPWorldMapEditorWidget.h"
  8→#include "LFP2D/UI/WorldMap/LFPUnitMergeWidget.h"
  9→#include "LFP2D/Core/LFPGameInstance.h"
 10→#include "Kismet/GameplayStatics.h"
 11→#include "Camera/PlayerCameraManager.h"
 12→#include "EnhancedInputComponent.h"
 13→#include "EnhancedInputSubsystems.h"
 14→
 15→ALFPWorldMapPlayerController::ALFPWorldMapPlayerController()
 16→{
 17→	CameraOffset = FVector::ZeroVector;
 18→
 19→	// 创建世界地图编辑器组件
 20→	WorldMapEditorComponent = CreateDefaultSubobject<ULFPWorldMapEditorComponent>(TEXT("WorldMapEditorComponent"));
 21→}
 22→
 23→void ALFPWorldMapPlayerController::BeginPlay()
 24→{
 25→	Super::BeginPlay();
 26→
 27→	// 设置输入模式
 28→	FInputModeGameAndUI InputMode;
 29→	InputMode.SetLockMouseToViewportBehavior(EMouseLockMode::DoNotLock);
 30→	InputMode.SetHideCursorDuringCapture(false);
 31→	SetInputMode(InputMode);
 32→	bShowMouseCursor = true;
 33→
 34→	// 设置 Enhanced Input
 35→	if (UEnhancedInputLocalPlayerSubsystem* Subsystem = ULocalPlayer::GetSubsystem<UEnhancedInputLocalPlayerSubsystem>(GetLocalPlayer()))
 36→	{
 37→		if (DefaultInputMapping)
 38→		{
 39→			Subsystem->AddMappingContext(DefaultInputMapping, 0);
 40→		}
 41→	}
 42→
 43→	// 场景切换淡入效果
 44→	if (PlayerCameraManager)
 45→	{
 46→		ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
 47→		float FadeDuration = GI ? GI->TransitionFadeDuration : 0.5f;
 48→		PlayerCameraManager->StartCameraFade(1.f, 0.f, FadeDuration, FLinearColor::Black, false, false);
 49→	}
 50→
 51→	// 首帧跳过相机平滑插值
 52→	bSnapCameraNextFrame = true;
 53→}
 54→
 55→void ALFPWorldMapPlayerController::Tick(float DeltaTime)
 56→{
 57→	Super::Tick(DeltaTime);
 58→
 59→	if (bIsDragging)
 60→	{
 61→		DragTime += DeltaTime;
 62→	}
 63→
 64→	// 更新相机位置和旋转
 65→	// 相机位置：CameraOffset（XY 平移）+ CurrentZoom（高度）
 66→	FVector TargetLocation = CameraOffset + FVector(0.f, 0.f, CurrentZoom);
 67→
 68→	// 相机旋转：俯视角
 69→	FRotator TargetRotation(CameraPitchAngle, 0.f, 0.f);
 70→
 71→	// 平滑插值并设置
 72→	FRotator CurrentRotation = GetControlRotation();
 73→	if (bSnapCameraNextFrame)
 74→	{
 75→		SetControlRotation(TargetRotation);
 76→	}
 77→	else
 78→	{
 79→		SetControlRotation(FMath::RInterpTo(CurrentRotation, TargetRotation, DeltaTime, 5.0f));
 80→	}
 81→
 82→	// 通过 Pawn 控制相机位置（如果有 Pawn）
 83→	if (APawn* ControlledPawn = GetPawn())
 84→	{
 85→		if (bSnapCameraNextFrame)
 86→		{
 87→			// 首帧直接跳到目标位置，避免切场景后相机大幅滑动
 88→			ControlledPawn->SetActorLocation(TargetLocation);
 89→			bSnapCameraNextFrame = false;
 90→		}
 91→		else
 92→		{
 93→			FVector CurrentLocation = ControlledPawn->GetActorLocation();
 94→			ControlledPawn->SetActorLocation(
 95→				FMath::VInterpTo(CurrentLocation, TargetLocation, DeltaTime, 5.0f)
 96→			);
 97→		}
 98→	}
 99→}
100→
101→void ALFPWorldMapPlayerController::SetupInputComponent()
102→{
103→	Super::SetupInputComponent();
104→
105→	if (UEnhancedInputComponent* EnhancedInputComponent = Cast<UEnhancedInputComponent>(InputComponent))
106→	{
107→		// 基础操作
108→		EnhancedInputComponent->BindAction(ConfirmAction, ETriggerEvent::Completed, this, &ALFPWorldMapPlayerController::OnConfirmAction);
109→		EnhancedInputComponent->BindAction(CancelAction, ETriggerEvent::Completed, this, &ALFPWorldMapPlayerController::OnCancelAction);
110→
111→		// 相机操作
112→		EnhancedInputComponent->BindAction(CameraPanAction, ETriggerEvent::Triggered, this, &ALFPWorldMapPlayerController::OnCameraPan);
113→		EnhancedInputComponent->BindAction(CameraDragAction, ETriggerEvent::Started, this, &ALFPWorldMapPlayerController::OnCameraDragStarted);
114→		EnhancedInputComponent->BindAction(CameraDragAction, ETriggerEvent::Triggered, this, &ALFPWorldMapPlayerController::OnCameraDragTriggered);
115→		EnhancedInputComponent->BindAction(CameraDragAction, ETriggerEvent::Completed, this, &ALFPWorldMapPlayerController::OnCameraDragCompleted);
116→		EnhancedInputComponent->BindAction(CameraZoomAction, ETriggerEvent::Triggered, this, &ALFPWorldMapPlayerController::OnCameraZoom);
117→
118→		// 编辑器切换
119→		EnhancedInputComponent->BindAction(ToggleEditorAction, ETriggerEvent::Started, this, &ALFPWorldMapPlayerController::OnToggleEditorAction);
120→	}
121→}
122→
123→// ============== 输入处理 ==============
124→
125→void ALFPWorldMapPlayerController::OnConfirmAction(const FInputActionValue& Value)
126→{
127→	bIsDragging = false;
128→	if (DragTime > DragThresholdTime)
129→	{
130→		DragTime = 0.f;
131→		return;
132→	}
133→	DragTime = 0.f;
134→
135→	// 编辑器模式优先处理
136→	if (WorldMapEditorComponent && WorldMapEditorComponent->IsEditorActive())
137→	{
138→		// 射线检测点击的节点
139→		FHitResult HitResult;
140→		GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
141→		ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
142→
143→		ELFPWorldMapEditorTool CurrentTool = WorldMapEditorComponent->GetCurrentTool();
144→
145→		switch (CurrentTool)
146→		{
147→		case ELFPWorldMapEditorTool::WMET_PlaceNode:
148→			{
149→				// 射线投射到 Z=0 平面获取世界坐标
150→				FVector WorldOrigin, WorldDirection;
151→				DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
152→				if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
153→				{
154→					float T = -WorldOrigin.Z / WorldDirection.Z;
155→					FVector HitPoint = WorldOrigin + WorldDirection * T;
156→					WorldMapEditorComponent->PlaceNodeAt(FVector2D(HitPoint.X, HitPoint.Y));
157→				}
158→			}
159→			break;
160→
161→		case ELFPWorldMapEditorTool::WMET_RemoveNode:
162→			if (ClickedNode)
163→			{
164→				WorldMapEditorComponent->SelectNode(ClickedNode);
165→				WorldMapEditorComponent->RemoveSelectedNode();
166→			}
167→			break;
168→
169→		case ELFPWorldMapEditorTool::WMET_MoveNode:
170→			if (ClickedNode)
171→			{
172→				WorldMapEditorComponent->SelectNode(ClickedNode);
173→			}
174→			else if (WorldMapEditorComponent->GetSelectedNode())
175→			{
176→				// 移动到点击位置
177→				FVector WorldOrigin, WorldDirection;
178→				DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
179→				if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
180→				{
181→					float T = -WorldOrigin.Z / WorldDirection.Z;
182→					FVector HitPoint = WorldOrigin + WorldDirection * T;
183→					WorldMapEditorComponent->MoveSelectedNodeTo(FVector2D(HitPoint.X, HitPoint.Y));
184→				}
