 10→void ULFPUnitMergeWidget::NativeConstruct()
 11→{
 12→	Super::NativeConstruct();
 13→
 14→	if (Button_SlotA) Button_SlotA->OnClicked.AddDynamic(this, &ULFPUnitMergeWidget::OnSlotAClicked);
