 23→void ULFPUnitMergeWidget::Setup(ULFPGameInstance* GI, ULFPUnitRegistryDataAsset* Registry)
 24→{
 25→	CachedGameInstance = GI;
 26→	CachedRegistry = Registry;
 27→	ClearSlots();
 28→	RefreshUnitIcons();
 29→}
 30→
 31→// 创建单个单位 icon 按钮的辅助函数
 32→static UButton* CreateUnitIconButton(ULFPUnitMergeWidget* Outer, UHorizontalBox* Container,
 33→	ULFPUnitRegistryDataAsset* Registry, const FLFPUnitEntry& Unit, bool bDisabled)
 34→{
 35→	UButton* Btn = NewObject<UButton>(Outer);
 36→	if (!Btn || !Container) return nullptr;
 37→
 38→	UHorizontalBoxSlot* BoxSlot = Container->AddChildToHorizontalBox(Btn);
 39→	if (BoxSlot)
 40→	{
 41→		BoxSlot->SetPadding(FMargin(4.f));
 42→	}
 43→
 44→	// 设置图标样式
 45→	FLFPUnitRegistryEntry RegEntry;
 46→	if (Registry && Registry->FindEntry(Unit.TypeID, RegEntry) && RegEntry.Icon)
 47→	{
 48→		FButtonStyle Style = Btn->GetStyle();
 49→		Style.Normal.SetResourceObject(RegEntry.Icon);
 50→		Style.Normal.ImageSize = FVector2D(64.f, 64.f);
 51→		Style.Hovered.SetResourceObject(RegEntry.Icon);
 52→		Style.Hovered.ImageSize = FVector2D(64.f, 64.f);
 53→		Style.Pressed.SetResourceObject(RegEntry.Icon);
 54→		Style.Pressed.ImageSize = FVector2D(64.f, 64.f);
 55→		Btn->SetStyle(Style);
 56→	}
 57→
 58→	if (bDisabled)
 59→	{
 60→		Btn->SetIsEnabled(false);
 61→		Btn->SetRenderOpacity(0.4f);
 62→	}
 63→
 64→	return Btn;
 65→}
 66→
 67→void ULFPUnitMergeWidget::RefreshUnitIcons()
 68→{
 69→	UnitIconButtons.Empty();
 70→	ButtonToUnitMap.Empty();
 71→
 72→	if (!CachedGameInstance || !CachedRegistry) return;
 73→
 74→	if (Box_PartyUnits) Box_PartyUnits->ClearChildren();
 75→	if (Box_ReserveUnits) Box_ReserveUnits->ClearChildren();
 76→
 77→	// 队伍单位
 78→	for (int32 i = 0; i < CachedGameInstance->PartyUnits.Num(); ++i)
 79→	{
 80→		const FLFPUnitEntry& Unit = CachedGameInstance->PartyUnits[i];
 81→		if (!Unit.IsValid()) continue;
 82→
 83→		bool bInSlot = (!SlotA.bIsEmpty && SlotA.bIsParty && SlotA.SlotIndex == i)
 84→			|| (!SlotB.bIsEmpty && SlotB.bIsParty && SlotB.SlotIndex == i);
 85→
 86→		UButton* Btn = CreateUnitIconButton(this, Box_PartyUnits, CachedRegistry, Unit, bInSlot);
 87→		if (!Btn) continue;
 88→
 89→		UnitIconButtons.Add(Btn);
 90→		ButtonToUnitMap.Add(Btn, {true, i});
 91→
 92→		if (!bInSlot)
 93→		{
 94→			Btn->OnClicked.AddDynamic(this, &ULFPUnitMergeWidget::OnUnitIconClicked);
 95→		}
 96→	}
 97→
 98→	// 备战营单位
 99→	for (int32 i = 0; i < CachedGameInstance->ReserveUnits.Num(); ++i)
100→	{
101→		const FLFPUnitEntry& Unit = CachedGameInstance->ReserveUnits[i];
102→		if (!Unit.IsValid()) continue;
103→
104→		bool bInSlot = (!SlotA.bIsEmpty && !SlotA.bIsParty && SlotA.SlotIndex == i)
105→			|| (!SlotB.bIsEmpty && !SlotB.bIsParty && SlotB.SlotIndex == i);
106→
107→		UButton* Btn = CreateUnitIconButton(this, Box_ReserveUnits, CachedRegistry, Unit, bInSlot);
108→		if (!Btn) continue;
109→
110→		UnitIconButtons.Add(Btn);
111→		ButtonToUnitMap.Add(Btn, {false, i});
112→
113→		if (!bInSlot)
114→		{
115→			Btn->OnClicked.AddDynamic(this, &ULFPUnitMergeWidget::OnUnitIconClicked);
116→		}
117→	}
118→}
119→
120→void ULFPUnitMergeWidget::OnUnitIconClicked()
121→{
122→	// 找到触发点击的按钮
123→	for (const auto& Pair : ButtonToUnitMap)
124→	{
125→		UButton* Btn = Pair.Key;
126→		if (Btn && Btn->IsHovered())
127→		{
128→			PlaceUnitInSlot(Pair.Value.bIsParty, Pair.Value.SlotIndex);
129→			return;
130→		}
131→	}
132→}
133→
134→void ULFPUnitMergeWidget::PlaceUnitInSlot(bool bIsParty, int32 Index)
135→{
136→	if (!CachedGameInstance) return;
137→
138→	const TArray<FLFPUnitEntry>& SourceArray = bIsParty
139→		? CachedGameInstance->PartyUnits
140→		: CachedGameInstance->ReserveUnits;
141→
142→	if (!SourceArray.IsValidIndex(Index)) return;
143→
144→	FLFPMergeSlotInfo NewSlot;
145→	NewSlot.bIsParty = bIsParty;
146→	NewSlot.SlotIndex = Index;
147→	NewSlot.Unit = SourceArray[Index];
148→	NewSlot.bIsEmpty = false;
149→
150→	// 放入第一个空的合成框
151→	if (SlotA.bIsEmpty)
152→	{
153→		SlotA = NewSlot;
154→	}
155→	else if (SlotB.bIsEmpty)
156→	{
157→		SlotB = NewSlot;
158→	}
159→	else
160→	{
161→		// 两个都满了，不操作
162→		return;
163→	}
164→
165→	UpdateSlotVisual(SlotA, Image_SlotA);
166→	UpdateSlotVisual(SlotB, Image_SlotB);
167→	UpdatePreview();
168→	RefreshUnitIcons();
169→}
