171→void ULFPUnitMergeWidget::OnSlotAClicked()
172→{
173→	if (!SlotA.bIsEmpty)
174→	{
175→		SlotA = FLFPMergeSlotInfo();
176→		UpdateSlotVisual(SlotA, Image_SlotA);
177→		UpdatePreview();
178→		RefreshUnitIcons();
179→	}
180→}
181→
182→void ULFPUnitMergeWidget::OnSlotBClicked()
183→{
184→	if (!SlotB.bIsEmpty)
185→	{
186→		SlotB = FLFPMergeSlotInfo();
187→		UpdateSlotVisual(SlotB, Image_SlotB);
188→		UpdatePreview();
189→		RefreshUnitIcons();
190→	}
191→}
192→
193→void ULFPUnitMergeWidget::ClearSlots()
194→{
195→	SlotA = FLFPMergeSlotInfo();
196→	SlotB = FLFPMergeSlotInfo();
197→	UpdateSlotVisual(SlotA, Image_SlotA);
198→	UpdateSlotVisual(SlotB, Image_SlotB);
199→	UpdatePreview();
200→}
201→
202→void ULFPUnitMergeWidget::UpdatePreview()
203→{
204→	bool bCanMerge = false;
205→	SelectedEvolutionTarget = NAME_None;
206→
207→	// 清空分支选择
208→	if (Box_EvolutionChoices) Box_EvolutionChoices->ClearChildren();
209→	EvolutionChoiceButtons.Empty();
210→	EvolutionButtonToTargetMap.Empty();
211→
212→	if (!SlotA.bIsEmpty && !SlotB.bIsEmpty && CachedRegistry)
213→	{
214→		// 检查匹配：同 TypeID
215→		if (SlotA.Unit.TypeID == SlotB.Unit.TypeID)
216→		{
217→			TArray<FName> Targets = CachedRegistry->GetEvolutionTargets(SlotA.Unit.TypeID);
218→
219→			if (Targets.Num() == 1)
220→			{
221→				// 唯一进化目标 → 直接显示预览
222→				SelectedEvolutionTarget = Targets[0];
223→				bCanMerge = true;
224→
225→				FLFPUnitRegistryEntry TargetEntry;
226→				if (CachedRegistry->FindEntry(SelectedEvolutionTarget, TargetEntry))
227→				{
228→					if (Image_PreviewIcon && TargetEntry.Icon)
229→					{
230→						Image_PreviewIcon->SetBrushFromTexture(TargetEntry.Icon);
231→						Image_PreviewIcon->SetRenderOpacity(1.f);
232→					}
233→					if (Text_PreviewName)
234→					{
235→						FString PreviewText = FString::Printf(TEXT("%s %s"),
236→							*TargetEntry.DisplayName.ToString(), *MakeTierStars(TargetEntry.Tier));
237→						Text_PreviewName->SetText(FText::FromString(PreviewText));
238→					}
239→				}
240→			}
241→			else if (Targets.Num() > 1)
242→			{
243→				// 多个进化目标 → 显示分支选择
244→				if (Text_PreviewName)
245→				{
246→					Text_PreviewName->SetText(FText::FromString(TEXT("请选择进化方向")));
247→				}
248→				if (Image_PreviewIcon)
249→				{
250→					Image_PreviewIcon->SetRenderOpacity(0.2f);
251→				}
252→
253→				// 为每个分支创建选择按钮
254→				for (const FName& TargetID : Targets)
255→				{
256→					FLFPUnitRegistryEntry TargetEntry;
257→					if (!CachedRegistry->FindEntry(TargetID, TargetEntry)) continue;
258→
259→					UButton* ChoiceBtn = NewObject<UButton>(this);
260→					if (!ChoiceBtn || !Box_EvolutionChoices) continue;
261→
262→					EvolutionChoiceButtons.Add(ChoiceBtn);
263→					EvolutionButtonToTargetMap.Add(ChoiceBtn, TargetID);
264→
265→					UHorizontalBoxSlot* BoxSlot = Box_EvolutionChoices->AddChildToHorizontalBox(ChoiceBtn);
266→					if (BoxSlot)
267→					{
268→						BoxSlot->SetPadding(FMargin(8.f));
269→					}
270→
271→					// 设置按钮图标
272→					if (TargetEntry.Icon)
273→					{
274→						FButtonStyle Style = ChoiceBtn->GetStyle();
275→						Style.Normal.SetResourceObject(TargetEntry.Icon);
276→						Style.Normal.ImageSize = FVector2D(80.f, 80.f);
277→						Style.Hovered.SetResourceObject(TargetEntry.Icon);
278→						Style.Hovered.ImageSize = FVector2D(80.f, 80.f);
279→						Style.Pressed.SetResourceObject(TargetEntry.Icon);
280→						Style.Pressed.ImageSize = FVector2D(80.f, 80.f);
281→						ChoiceBtn->SetStyle(Style);
282→					}
283→
284→					ChoiceBtn->OnClicked.AddDynamic(this, &ULFPUnitMergeWidget::OnEvolutionChoiceClicked);
285→				}
286→			}
287→			else
288→			{
289→				// 无进化目标（终阶）
290→				if (Text_PreviewName)
291→				{
292→					Text_PreviewName->SetText(FText::FromString(TEXT("已达终阶")));
293→				}
294→				if (Image_PreviewIcon)
295→				{
296→					Image_PreviewIcon->SetRenderOpacity(0.2f);
297→				}
298→			}
299→		}
300→		else
301→		{
302→			// TypeID 不同
303→			if (Text_PreviewName)
304→			{
305→				Text_PreviewName->SetText(FText::FromString(TEXT("无法合并")));
306→			}
307→			if (Image_PreviewIcon)
308→			{
309→				Image_PreviewIcon->SetRenderOpacity(0.2f);
310→			}
311→		}
312→	}
313→	else
314→	{
315→		// 合成框未满
316→		if (Text_PreviewName)
317→		{
318→			Text_PreviewName->SetText(FText::FromString(TEXT("请选择两个相同单位")));
319→		}
320→		if (Image_PreviewIcon)
321→		{
322→			Image_PreviewIcon->SetRenderOpacity(0.2f);
323→		}
324→	}
325→
326→	if (Button_Merge)
327→	{
328→		Button_Merge->SetIsEnabled(bCanMerge);
329→	}
330→}
331→
332→void ULFPUnitMergeWidget::OnEvolutionChoiceClicked()
333→{
334→	// 找到点击的分支按钮
335→	for (const auto& Pair : EvolutionButtonToTargetMap)
336→	{
337→		if (Pair.Key && Pair.Key->IsHovered())
338→		{
339→			SelectedEvolutionTarget = Pair.Value;
340→
341→			// 更新预览为选中的目标
342→			FLFPUnitRegistryEntry TargetEntry;
343→			if (CachedRegistry && CachedRegistry->FindEntry(SelectedEvolutionTarget, TargetEntry))
344→			{
345→				if (Image_PreviewIcon && TargetEntry.Icon)
346→				{
347→					Image_PreviewIcon->SetBrushFromTexture(TargetEntry.Icon);
348→					Image_PreviewIcon->SetRenderOpacity(1.f);
349→				}
350→				if (Text_PreviewName)
351→				{
352→					FString PreviewText = FString::Printf(TEXT("%s %s"),
353→						*TargetEntry.DisplayName.ToString(), *MakeTierStars(TargetEntry.Tier));
354→					Text_PreviewName->SetText(FText::FromString(PreviewText));
355→				}
356→			}
357→
358→			// 启用合并按钮
359→			if (Button_Merge)
360→			{
361→				Button_Merge->SetIsEnabled(true);
362→			}
363→			return;
364→		}
365→	}
366→}
367→
368→void ULFPUnitMergeWidget::OnMergeClicked()
369→{
370→	if (!CachedGameInstance || SlotA.bIsEmpty || SlotB.bIsEmpty) return;
371→	if (SelectedEvolutionTarget == NAME_None) return;
372→
373→	bool bSuccess = CachedGameInstance->MergeUnits(
374→		SlotA.bIsParty, SlotA.SlotIndex,
375→		SlotB.bIsParty, SlotB.SlotIndex,
376→		SelectedEvolutionTarget);
377→
378→	if (bSuccess)
379→	{
380→		UE_LOG(LogTemp, Log, TEXT("升阶 Widget: 进化成功 → %s"), *SelectedEvolutionTarget.ToString());
381→	}
382→
383→	ClearSlots();
384→	RefreshUnitIcons();
385→}
386→
387→void ULFPUnitMergeWidget::OnClearClicked()
388→{
389→	ClearSlots();
390→	RefreshUnitIcons();
391→}
392→
393→void ULFPUnitMergeWidget::OnCloseClicked()
394→{
395→	OnClosed.Broadcast();
396→	RemoveFromParent();
397→}
398→
399→void ULFPUnitMergeWidget::UpdateSlotVisual(const FLFPMergeSlotInfo& InSlot, UImage* SlotImage)
400→{
401→	if (!SlotImage) return;
402→
403→	if (InSlot.bIsEmpty)
404→	{
405→		SlotImage->SetRenderOpacity(0.2f);
406→		SlotImage->SetBrushFromTexture(nullptr);
407→	}
408→	else if (CachedRegistry)
409→	{
410→		FLFPUnitRegistryEntry RegEntry;
411→		if (CachedRegistry->FindEntry(InSlot.Unit.TypeID, RegEntry) && RegEntry.Icon)
412→		{
413→			SlotImage->SetBrushFromTexture(RegEntry.Icon);
414→			SlotImage->SetRenderOpacity(1.f);
415→		}
416→	}
417→}
