187→TArray<FLFPUnitEntry> ULFPGameInstance::GetMergeablePairs() const
188→{
189→	// 统计每个 TypeID 的出现次数
190→	TMap<FName, int32> CountMap;
191→
192→	for (const FLFPUnitEntry& Unit : PartyUnits)
193→	{
194→		if (Unit.IsValid())
195→		{
196→			CountMap.FindOrAdd(Unit.TypeID, 0)++;
197→		}
198→	}
199→	for (const FLFPUnitEntry& Unit : ReserveUnits)
200→	{
201→		if (Unit.IsValid())
202→		{
203→			CountMap.FindOrAdd(Unit.TypeID, 0)++;
204→		}
205→	}
206→
207→	// 筛选出现 >= 2 次且注册表中有进化目标的 TypeID
208→	TArray<FLFPUnitEntry> Result;
209→	for (const auto& Pair : CountMap)
210→	{
211→		if (Pair.Value >= 2 && UnitRegistry && UnitRegistry->CanEvolve(Pair.Key))
212→		{
213→			FLFPUnitEntry Entry;
214→			Entry.TypeID = Pair.Key;
215→			Entry.Tier = UnitRegistry->GetUnitTier(Pair.Key);
216→			Result.Add(Entry);
217→		}
218→	}
