223→bool ULFPGameInstance::MergeUnits(bool bSourceAIsParty, int32 SourceAIndex,
224→	bool bSourceBIsParty, int32 SourceBIndex, FName TargetTypeID)
225→{
226→	TArray<FLFPUnitEntry>& ArrayA = bSourceAIsParty ? PartyUnits : ReserveUnits;
227→	TArray<FLFPUnitEntry>& ArrayB = bSourceBIsParty ? PartyUnits : ReserveUnits;
228→
229→	if (!ArrayA.IsValidIndex(SourceAIndex) || !ArrayB.IsValidIndex(SourceBIndex))
230→	{
231→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 无效的槽位索引"));
232→		return false;
233→	}
234→
235→	const FLFPUnitEntry& UnitA = ArrayA[SourceAIndex];
236→	const FLFPUnitEntry& UnitB = ArrayB[SourceBIndex];
237→
238→	// 验证两个源单位 TypeID 相同
239→	if (UnitA.TypeID != UnitB.TypeID)
240→	{
241→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 单位类型不匹配 (%s vs %s)"),
242→			*UnitA.TypeID.ToString(), *UnitB.TypeID.ToString());
243→		return false;
244→	}
245→
246→	// 验证 TargetTypeID 在进化目标列表中
247→	if (!UnitRegistry)
248→	{
249→		UE_LOG(LogTemp, Error, TEXT("MergeUnits: 注册表未配置"));
250→		return false;
251→	}
252→
253→	TArray<FName> Targets = UnitRegistry->GetEvolutionTargets(UnitA.TypeID);
254→	if (!Targets.Contains(TargetTypeID))
255→	{
256→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: %s 不是 %s 的有效进化目标"),
257→			*TargetTypeID.ToString(), *UnitA.TypeID.ToString());
258→		return false;
259→	}
260→
261→	// 创建进化后的新单位
262→	FLFPUnitEntry NewUnit;
263→	NewUnit.TypeID = TargetTypeID;
