{
	if (EditorComponent) EditorComponent->SetBrushCanEscape(bIsChecked);
}

void ULFPWorldMapEditorWidget::OnBattleMapNameChanged(const FText& Text, ETextCommit::Type CommitType)
{
	if (EditorComponent) EditorComponent->SetBrushBattleMapName(Text.ToString());
}

void ULFPWorldMapEditorWidget::OnEventIDChanged(const FText& Text, ETextCommit::Type CommitType)
{
	if (EditorComponent) EditorComponent->SetBrushEventID(Text.ToString());
}

void ULFPWorldMapEditorWidget::OnEdgeTurnCostChanged(const FText& Text, ETextCommit::Type CommitType)
{
	if (!EditorComponent) return;
	int32 Cost = FCString::Atoi(*Text.ToString());
	EditorComponent->SetBrushEdgeTurnCost(Cost);
}

void ULFPWorldMapEditorWidget::OnBaseGoldRewardChanged(const FText& Text, ETextCommit::Type CommitType)
{
	if (!EditorComponent) return;
	int32 Gold = FCString::Atoi(*Text.ToString());
	EditorComponent->SetBrushBaseGoldReward(Gold);
}

void ULFPWorldMapEditorWidget::OnBaseFoodRewardChanged(const FText& Text, ETextCommit::Type CommitType)
{
	if (!EditorComponent) return;
	int32 Food = FCString::Atoi(*Text.ToString());
	EditorComponent->SetBrushBaseFoodReward(Food);
}

// ============== 保存/加载 ==============

void ULFPWorldMapEditorWidget::OnSaveClicked()
{
	if (!EditorComponent || !WorldMapFileNameInput) return;

	FString MapName = WorldMapFileNameInput->GetText().ToString();
	if (MapName.IsEmpty())
	{
		UE_LOG(LogTemp, Warning, TEXT("世界地图编辑器: 请输入文件名"));
		return;
	}

	if (EditorComponent->SaveWorldMap(MapName))
	{
		UE_LOG(LogTemp, Log, TEXT("世界地图编辑器: 保存成功 - %s"), *MapName);
	}
}

void ULFPWorldMapEditorWidget::OnLoadClicked()
{
	if (!EditorComponent || !WorldMapFileNameInput) return;

	FString MapName = WorldMapFileNameInput->GetText().ToString();
	if (MapName.IsEmpty())
	{
		UE_LOG(LogTemp, Warning, TEXT("世界地图编辑器: 请输入文件名"));
		return;
	}

	if (EditorComponent->LoadWorldMap(MapName))
	{
		UE_LOG(LogTemp, Log, TEXT("世界地图编辑器: 加载成功 - %s"), *MapName);
	}
}

void ULFPWorldMapEditorWidget::OnNewMapClicked()
{
	if (EditorComponent) EditorComponent->NewWorldMap();
}

// ============== UI 更新 ==============

void ULFPWorldMapEditorWidget::UpdateToolIndicator(ELFPWorldMapEditorTool NewTool)
{
	if (!CurrentToolText) return;

	static const TMap<ELFPWorldMapEditorTool, FString> ToolNames = {
		{ELFPWorldMapEditorTool::WMET_None, TEXT("无")},
		{ELFPWorldMapEditorTool::WMET_PlaceNode, TEXT("放置节点")},
		{ELFPWorldMapEditorTool::WMET_RemoveNode, TEXT("删除节点")},
		{ELFPWorldMapEditorTool::WMET_MoveNode, TEXT("移动节点")},
		{ELFPWorldMapEditorTool::WMET_ConnectEdge, TEXT("连接边")},
		{ELFPWorldMapEditorTool::WMET_RemoveEdge, TEXT("删除边")},
		{ELFPWorldMapEditorTool::WMET_SetNodeParams, TEXT("设置参数")},
		{ELFPWorldMapEditorTool::WMET_EditBattleMap, TEXT("编辑战斗地图")},
	};

	if (const FString* Name = ToolNames.Find(NewTool))
	{
		CurrentToolText->SetText(FText::FromString(*Name));
	}
}

void ULFPWorldMapEditorWidget::UpdateNodeInfo(ALFPWorldMapNode* Node)
{
	if (!SelectedNodeInfoText) return;

	if (!Node)
	{
		SelectedNodeInfoText->SetText(FText::FromString(TEXT("未选中")));
		return;
	}

	// 节点类型名
	FString TypeStr = UEnum::GetValueAsString(Node->NodeType);
	TypeStr = TypeStr.RightChop(TypeStr.Find(TEXT("::")) + 2);

	FString Info = FString::Printf(TEXT("ID: %d | 类型: %s"), Node->NodeID, *TypeStr);

	if (Node->NodeType == ELFPWorldNodeType::WNT_Battle)
	{
		Info += FString::Printf(TEXT(" | 星级: %d | 地图: %s | 金币: %d | 食物: %d"),
			Node->StarRating, *Node->BattleMapName, Node->BaseGoldReward, Node->BaseFoodReward);
	}
	else if (Node->NodeType == ELFPWorldNodeType::WNT_Event)
	{
		Info += FString::Printf(TEXT(" | 事件: %s"), *Node->EventID);
	}

	SelectedNodeInfoText->SetText(FText::FromString(Info));
}

#pragma once

#include "CoreMinimal.h"
#include "Components/ActorComponent.h"
#include "LFP2D/WorldMap/LFPWorldMapData.h"
#include "LFPWorldMapEditorComponent.generated.h"

class ALFPWorldMapManager;
class ALFPWorldMapNode;
class ALFPWorldMapEdge;

// 世界地图编辑器工具模式
UENUM(BlueprintType)
enum class ELFPWorldMapEditorTool : uint8
{
	WMET_None           UMETA(DisplayName = "无"),
	WMET_PlaceNode      UMETA(DisplayName = "放置节点"),
	WMET_RemoveNode     UMETA(DisplayName = "删除节点"),
	WMET_MoveNode       UMETA(DisplayName = "移动节点"),
	WMET_ConnectEdge    UMETA(DisplayName = "连接边"),
	WMET_RemoveEdge     UMETA(DisplayName = "删除边"),
	WMET_SetNodeParams  UMETA(DisplayName = "设置节点参数"),
	WMET_EditBattleMap  UMETA(DisplayName = "编辑战斗地图")
};

DECLARE_DYNAMIC_MULTICAST_DELEGATE_OneParam(FOnWorldEditorToolChanged, ELFPWorldMapEditorTool, NewTool);
DECLARE_DYNAMIC_MULTICAST_DELEGATE_OneParam(FOnWorldEditorModeChanged, bool, bEditorActive);
DECLARE_DYNAMIC_MULTICAST_DELEGATE_OneParam(FOnWorldEditorNodeSelected, ALFPWorldMapNode*, SelectedNode);

/**
 * 世界地图编辑器组件：管理编辑器状态、工具切换、笔刷参数
 * 挂载在 PlayerController 上
 */
UCLASS(Blueprintable, ClassGroup=(WorldMapEditor), meta=(BlueprintSpawnableComponent))
class LFP2D_API ULFPWorldMapEditorComponent : public UActorComponent
{
	GENERATED_BODY()

public:
	ULFPWorldMapEditorComponent();

	// 切换编辑器模式
	UFUNCTION(BlueprintCallable, Category = "World Map Editor")
	void ToggleEditorMode();

	UFUNCTION(BlueprintPure, Category = "World Map Editor")
	bool IsEditorActive() const { return bEditorActive; }

	// 设置工具
	UFUNCTION(BlueprintCallable, Category = "World Map Editor")
	void SetCurrentTool(ELFPWorldMapEditorTool Tool);

	UFUNCTION(BlueprintPure, Category = "World Map Editor")
	ELFPWorldMapEditorTool GetCurrentTool() const { return CurrentTool; }

	// ==== 笔刷参数 ====

	UFUNCTION(BlueprintCallable, Category = "World Map Editor|Brush")
	void SetBrushNodeType(ELFPWorldNodeType InType) { BrushNodeType = InType; }

	UFUNCTION(BlueprintCallable, Category = "World Map Editor|Brush")
	void SetBrushStarRating(int32 InRating) { BrushStarRating = FMath::Clamp(InRating, 1, 5); }

	UFUNCTION(BlueprintCallable, Category = "World Map Editor|Brush")
	void SetBrushCanEscape(bool bInCanEscape) { BrushCanEscape = bInCanEscape; }

	UFUNCTION(BlueprintCallable, Category = "World Map Editor|Brush")
	void SetBrushBattleMapName(const FString& InName) { BrushBattleMapName = InName; }

	UFUNCTION(BlueprintCallable, Category = "World Map Editor|Brush")
	void SetBrushEventID(const FString& InID) { BrushEventID = InID; }

	UFUNCTION(BlueprintCallable, Category = "World Map Editor|Brush")
	void SetBrushEdgeTurnCost(int32 InCost) { BrushEdgeTurnCost = FMath::Max(1, InCost); }

	UFUNCTION(BlueprintCallable, Category = "World Map Editor|Brush")
	void SetBrushBaseGoldReward(int32 InGold) { BrushBaseGoldReward = FMath::Max(0, InGold); }

	UFUNCTION(BlueprintCallable, Category = "World Map Editor|Brush")
	void SetBrushBaseFoodReward(int32 InFood) { BrushBaseFoodReward = FMath::Max(0, InFood); }

	// ==== 操作方法 ====

	// 在世界坐标处放置新节点
	UFUNCTION(BlueprintCallable, Category = "World Map Editor")
	ALFPWorldMapNode* PlaceNodeAt(FVector2D WorldPos);

	// 选中已有节点（用于移动/连接/编辑参数）
	UFUNCTION(BlueprintCallable, Category = "World Map Editor")
	void SelectNode(ALFPWorldMapNode* Node);

	// 对选中节点应用参数（SetNodeParams 工具）
	UFUNCTION(BlueprintCallable, Category = "World Map Editor")
	void ApplyParamsToSelectedNode();

	// 开始连接边（第一次点击选中 FromNode，第二次点击选中 ToNode）
	UFUNCTION(BlueprintCallable, Category = "World Map Editor")
	void HandleEdgeConnection(ALFPWorldMapNode* Node);

	// 移动选中节点到新位置
	UFUNCTION(BlueprintCallable, Category = "World Map Editor")
	void MoveSelectedNodeTo(FVector2D NewPos);

	// 删除选中节点
	UFUNCTION(BlueprintCallable, Category = "World Map Editor")
	void RemoveSelectedNode();

	// 删除边（点击两个节点）
	UFUNCTION(BlueprintCallable, Category = "World Map Editor")
	void HandleEdgeRemoval(ALFPWorldMapNode* Node);

	// 进入战斗地图编辑（切换到内层编辑器）
	UFUNCTION(BlueprintCallable, Category = "World Map Editor")
	void EnterBattleMapEditor();

	// 从战斗地图编辑返回
	UFUNCTION(BlueprintCallable, Category = "World Map Editor")
	void ReturnFromBattleMapEditor();

	// 保存/加载
	UFUNCTION(BlueprintCallable, Category = "World Map Editor")
	bool SaveWorldMap(const FString& MapName);

	UFUNCTION(BlueprintCallable, Category = "World Map Editor")
	bool LoadWorldMap(const FString& MapName);

	UFUNCTION(BlueprintCallable, Category = "World Map Editor")
	TArray<FString> GetSavedWorldMapList();

	// 新建空白世界地图
	UFUNCTION(BlueprintCallable, Category = "World Map Editor")
	void NewWorldMap();

	// ==== 委托 ====

	UPROPERTY(BlueprintAssignable, Category = "World Map Editor")
	FOnWorldEditorToolChanged OnToolChanged;

	UPROPERTY(BlueprintAssignable, Category = "World Map Editor")
	FOnWorldEditorModeChanged OnEditorModeChanged;

	UPROPERTY(BlueprintAssignable, Category = "World Map Editor")
	FOnWorldEditorNodeSelected OnNodeSelected;

	// 获取选中节点
	UFUNCTION(BlueprintPure, Category = "World Map Editor")
	ALFPWorldMapNode* GetSelectedNode() const { return SelectedNode; }

	// 是否正在编辑战斗地图
	UFUNCTION(BlueprintPure, Category = "World Map Editor")
	bool IsEditingBattleMap() const { return bIsEditingBattleMap; }

protected:
	virtual void BeginPlay() override;

